const period = '2025-10';
if (!/^\d{4}-\d{2}$/.test(period)) throw new Error('Periodo invalido (YYYY-MM)');

return [{ json: {
  mode: 'MANUAL',
  period,
  dlRoot: '/data/ChileCompraDL',
  inboxLic: `/data/ChileCompraDL/02_INBOX/LIC/${period}`,
  inboxOc: `/data/ChileCompraDL/02_INBOX/OC/${period}`,
  composeBase: '/tfm/docker-compose.yml',
  composeN8n: '/tfm/docker-compose.n8n.yml'
} }];

// Garantiza exactamente 1 contexto valido antes de ejecutar shell
if (!items || items.length === 0) throw new Error('[FATAL] No llegó ningún item a Normalize Context');
if (items.length > 1) throw new Error('[FATAL] Llegaron múltiples items. Debe operar con 1 solo contexto.');

const ctx = items[0].json;
const required = ['mode','period','dlRoot','inboxLic','inboxOc','composeBase','composeN8n'];

for (const k of required) if (!ctx[k]) throw new Error(`[FATAL] Falta campo obligatorio: ${k}`);
if (!/^\d{4}-\d{2}$/.test(ctx.period)) throw new Error(`[FATAL] Periodo inválido: ${ctx.period}`);

return [{ json: { ...ctx, _normalized: true, _ts: new Date().toISOString() } }];

const s = items[0].json.stdout;
if (!s) throw new Error('[FATAL] Extract Context: stdout vacío (no hay JSON)');
let ctx;
try { ctx = JSON.parse(s); } catch (e) { throw new Error('[FATAL] Extract Context: stdout no es JSON válido'); }
return [{ json: { ...ctx } }];

const s = items[0].json.stdout;
if (!s) throw new Error('[FATAL] Extract Context: stdout vacío (no hay JSON)');
let ctx;
try { ctx = JSON.parse(s); } catch (e) { throw new Error('[FATAL] Extract Context: stdout no es JSON válido'); }
return [{ json: { ...ctx } }];

const raw = items?.[0]?.json?.stdout;
if (!raw) throw new Error('[FATAL] Extract Context: stdout vacío');
const lines = raw.trim().split('\n').map(l => l.trim()).filter(Boolean);
let candidate = lines[lines.length - 1];
for (let i = lines.length - 1; i >= 0; i--) {
  if (lines[i].startsWith('{') && lines[i].endsWith('}')) { candidate = lines[i]; break; }
}
let ctx;
try { ctx = JSON.parse(candidate); } catch (e) {
  throw new Error(`[FATAL] stdout no contiene JSON válido.\n${candidate}`);
}
return [{ json: ctx }];

const reasonMap = {
  MISSING_DIR: 'Faltan directorios INBOX',
  MISSING_FILE: 'Faltan archivos esperados (LIC_YYYY-MM.csv / OC_YYYY-MM.csv)',
  LIC_SCHEMA_ANOM: 'EXCEPCION_FUENTE: LIC esquema anómalo (cols < 50) — excluido (ej. 2025-01)',
  OC_SIZE_ANOM: 'OC tamaño anómalo (bytes < 5MB) — excluido (ej. 2025-03)',
  OC_LINES_ANOM: 'OC filas anómalas (lines < 1000) — excluido',
  OK: 'OK'
};

const reasonText = reasonMap[$json.reason] || `${$json.decision || 'NO_OP'}: ${$json.reason}`;

return [{ json: {
  decision: $json.decision || 'NO_OP',
  period: $json.period,
  reason: reasonText,
  reasonCode: $json.reason,
  reasonText,
  licFile: $json.licFile,
  ocFile: $json.ocFile,
  licCols: $json.licCols,
  ocBytes: $json.ocBytes,
  ocLines: $json.ocLines
}}];

// Clasifica RUN / NO_OP / EXCEPCION_FUENTE
// Regla: 2025-01 con LIC_SCHEMA_ANOM => EXCEPCION_FUENTE
// Todo lo demás que no sea RUN => NO_OP

const period = $json.period;
const baseDecision = $json.decision || 'NO_OP';
const reasonCode = $json.reason || '';

let decision = baseDecision;

if (period === '2025-01' && reasonCode === 'LIC_SCHEMA_ANOM') {
  decision = 'EXCEPCION_FUENTE';
}

return [{
  json: {
    ...$json,
    decision,
    decisionGroup: decision === 'RUN' ? 'RUN' : 'SKIP'
  }
}];
